object AWSServiceExample {
  
  def main(args: Array[String]): Unit = {
    val credentials = StaticCredentials("your-access-key", "your-secret-key")
    val serviceManager = new AWSServiceManager(credentials, Region.US_EAST_1)
    
    serviceManager.s3Service.createBucket("my-test-bucket") match {
      case Success(response) => println(s"Bucket created: ${response.location()}")
      case Failure(exception) => println(s"Failed to create bucket: ${exception.getMessage}")
    }
    
    serviceManager.s3Service.uploadData("my-test-bucket", "test.txt", "Hello AWS!") match {
      case Success(_) => println("File uploaded successfully")
      case Failure(exception) => println(s"Failed to upload: ${exception.getMessage}")
    }
    
    serviceManager.s3Service.listBuckets() match {
      case Success(buckets) => println(s"Buckets: ${buckets.mkString(", ")}")
      case Failure(exception) => println(s"Failed to list buckets: ${exception.getMessage}")
    }
    
    val hashKey = AttributeValue.builder().s("id").build()
    serviceManager.dynamoDBService.createTable("my-table", "id") match {
      case Success(_) => println("Table created successfully")
      case Failure(exception) => println(s"Failed to create table: ${exception.getMessage}")
    }
    
    val item = Map(
      "id" -> AttributeValue.builder().s("123").build(),
      "name" -> AttributeValue.builder().s("Test Item").build()
    )
    serviceManager.dynamoDBService.putItem("my-table", item) match {
      case Success(_) => println("Item added successfully")
      case Failure(exception) => println(s"Failed to add item: ${exception.getMessage}")
    }
    
    serviceManager.sqsService.createQueue("my-queue") match {
      case Success(queueUrl) => 
        println(s"Queue created: $queueUrl")
        serviceManager.sqsService.sendMessage(queueUrl, "Hello SQS!") match {
          case Success(response) => println(s"Message sent: ${response.messageId()}")
          case Failure(exception) => println(s"Failed to send message: ${exception.getMessage}")
        }
      case Failure(exception) => println(s"Failed to create queue: ${exception.getMessage}")
    }
    
    serviceManager.closeAll()
  }
}